import { readFile, writeFile } from "node:fs/promises";

const sources = [
  "src/questionExpansion.js",
  "src/geniusQuestions.js",
  "src/questions.js",
  "src/microcopy.js",
  "src/audio.js",
  "src/accountApi.js",
  "src/storage.js",
  "src/app.js"
];

function toClassicScript(source) {
  return source
    .replace(/import\s+\{[\s\S]*?\}\s+from\s+["'][^"']+["'];\n/g, "")
    .replace(/^export\s+async\s+function\s+/gm, "async function ")
    .replace(/^export\s+(const|function)\s+/gm, "$1 ");
}

const banner = `/* Generated by scripts/build-browser-bundle.mjs. Edit source modules, then rebuild. */\n`;
const body = [];

for (const sourcePath of sources) {
  const source = await readFile(sourcePath, "utf8");
  body.push(`\n/* ${sourcePath} */\n${toClassicScript(source)}`);
}

await writeFile("src/app.bundle.js", `${banner}${body.join("\n")}\n`, "utf8");
console.log("Built src/app.bundle.js");
